def affordance_score(skill, observation):
    """Learned value: can this skill succeed from the current state? (0..1)"""
    ...  # call a value network over the current image/state

def choose_skill(instruction, observation):
    scored = [(s, llm_score(instruction, s) * affordance_score(s, observation))
              for s in SKILLS]
    return max(scored, key=lambda x: x[1])[0]

def run_episode(instruction, robot, max_steps=15):
    for _ in range(max_steps):
        obs = robot.observe()
        skill = choose_skill(instruction, obs)
        if skill == "done":
            break
        robot.execute(skill)   # runs the learned low-level policy

# Sketch of a VLA inference step: pixels + instruction -> action tokens.
def vla_step(model, image, instruction, proprio):
    tokens = model.encode(image=image, text=instruction, state=proprio)
    action_tokens = model.decode_actions(tokens)      # e.g. 7 DoF, discretised
    return detokenize(action_tokens)                  # -> continuous joint deltas

def rollout(model, robot, instruction, horizon=200):
    for _ in range(horizon):
        img, proprio = robot.sense()
        action = vla_step(model, img, instruction, proprio)
        robot.apply(action)
